for (const item of $input.all()) {
  const originalTimestamp = new Date(item.json.timestamp);
  const newTimestamp = new Date(originalTimestamp.getTime() - 24 * 60 * 60 * 1000); // Add 24 hours
  item.json.newTimestamp = newTimestamp.toISOString(); // or .toLocaleString() if preferred
}
return $input.all();

const output = [];

for (const item of $input.all()) {
  const data = item.json;

  const extracted = {
    saleOrderId: data.saleOrderSeq || data.id,
    customer: data.clientPartner?.fullName || "Unknown",
    products: (data.saleOrderLineList || []).map(p => p.fullName),
    exTaxTotal: data.exTaxTotal,
    taxTotal: data.taxTotal,
    inTaxTotal: data.inTaxTotal,
    invoiceAddress: data.mainInvoicingAddressStr?.replace(/\n/g, ", ") || "N/A",
    currency: data.currency?.name || "N/A",
    createdOn: data.creationDate || data.createdOn,
    paymentTerms: data.paymentCondition?.name || "N/A",
    paymentMode: data.paymentMode?.name || "N/A"
  };

  output.push(extracted);
}

return [{json:{orders:output}}];
